// ── Sub-rhythm → human label map ────────────────────────────────────────
const RHYTHM_LABELS = {
  'angola':            'Angola',
  'sao-bento-pequeno': 'São Bento Pequeno',
  'sao-bento-grande':  'São Bento Grande',
  'iuna':              'Iúna',
  'cavalaria':         'Cavalaria',
  'benguela':          'Benguela',
};

// ── App state ────────────────────────────────────────────────────────────
let activeCategory = 'all';        // 'all' | 'capoeira' | 'samba' | 'maculele'
let activeRhythm   = 'all';        // 'all' | sub-rhythm key
let searchQuery    = '';
let isPlaying      = false;
let playbackRate   = 1.0;
let masterVolume   = 1.0;
// instrument mute map  key → false means active (unmuted), true means muted
const mutedMap  = { gunga: false, medio: false, viola: false, pandeiro: false, atabaque: false, palmas: false };
// instrument volume map  key → 0.0–1.0
const volumeMap = { gunga: 1.0, medio: 1.0, viola: 1.0, pandeiro: 1.0, atabaque: 1.0, palmas: 1.0 };

// ── DOM refs ─────────────────────────────────────────────────────────────
const songList        = document.getElementById('song-list');
const topTabs         = document.querySelectorAll('.top-tab');
const subNav          = document.getElementById('sub-nav');
const subTabs         = document.querySelectorAll('.sub-tab');
const mixer           = document.getElementById('mixer');
const mixerRhythmLbl  = document.getElementById('mixer-rhythm-label');
const playBtn         = document.getElementById('play-btn');
const speedSlider     = document.getElementById('speed-slider');
const speedDisplay    = document.getElementById('speed-display');
const searchInput     = document.getElementById('search-input');
const instBtns        = document.querySelectorAll('.inst-btn');
const volSliders      = document.querySelectorAll('.vol-slider');
const masterVolSlider = document.getElementById('master-vol-slider');
const masterVolDisplay= document.getElementById('master-vol-display');
const videoPlayerArea = document.getElementById('video-player-area');
const nowPlayingTitle = document.getElementById('now-playing-title');
const queueListEl     = document.getElementById('queue-list');

// ── Top-tab click ────────────────────────────────────────────────────────
topTabs.forEach(btn => {
  btn.addEventListener('click', () => {
    topTabs.forEach(b => { b.classList.remove('active'); b.setAttribute('aria-selected', 'false'); });
    btn.classList.add('active');
    btn.setAttribute('aria-selected', 'true');
    activeCategory = btn.dataset.category;

    if (activeCategory === 'capoeira') {
      subNav.removeAttribute('hidden');
      // Ensure "All Songs" sub-tab is active when switching to Capoeira
      if (!activeRhythm || activeRhythm === null) {
        activeRhythm = 'all';
        subTabs.forEach(s => {
          const isAll = s.dataset.rhythm === 'all';
          s.classList.toggle('active', isAll);
          s.setAttribute('aria-selected', isAll ? 'true' : 'false');
        });
        hideMixer();
      }
    } else {
      subNav.setAttribute('hidden', '');
      subTabs.forEach(s => { s.classList.remove('active'); s.setAttribute('aria-selected', 'false'); });
      activeRhythm = 'all';
      hideMixer();
    }

    renderSongs();
  });
});

// ── Sub-tab click ────────────────────────────────────────────────────────
subTabs.forEach(btn => {
  btn.addEventListener('click', async () => {
    const rhythm = btn.dataset.rhythm;
    if (activeRhythm === rhythm) return; // already active, do nothing

    subTabs.forEach(s => { s.classList.remove('active'); s.setAttribute('aria-selected', 'false'); });
    btn.classList.add('active');
    btn.setAttribute('aria-selected', 'true');
    activeRhythm = rhythm;

    if (rhythm === 'all' || rhythm === 'ladainha') {
      hideMixer();
    } else {
      await showMixer(rhythm);
    }

    renderSongs();
  });
});

// ── Web Audio engine ─────────────────────────────────────────────────────
let audioCtx       = null;
let masterGainNode = null;
let loadedRhythm   = null;
const stemAudio    = {};   // inst → HTMLAudioElement
const stemSrcs     = {};   // inst → MediaElementAudioSourceNode
const instGains    = {};   // inst → GainNode

const INST_KEYS = ['gunga','medio','viola','pandeiro','atabaque','palmas'];

function ensureAudioCtx() {
  if (audioCtx) return;
  audioCtx = new (window.AudioContext || window.webkitAudioContext)();
  masterGainNode = audioCtx.createGain();
  masterGainNode.gain.value = masterVolume;
  masterGainNode.connect(audioCtx.destination);
  INST_KEYS.forEach(inst => {
    const g = audioCtx.createGain();
    g.gain.value = mutedMap[inst] ? 0 : volumeMap[inst];
    g.connect(masterGainNode);
    instGains[inst] = g;
  });
}

async function loadStems(rhythm) {
  if (loadedRhythm === rhythm) return;
  stopPlayback();
  // Release old audio elements
  INST_KEYS.forEach(inst => {
    if (stemAudio[inst]) { stemAudio[inst].pause(); stemAudio[inst].src = ''; }
    if (stemSrcs[inst])  { stemSrcs[inst].disconnect(); }
    delete stemAudio[inst];
    delete stemSrcs[inst];
  });
  loadedRhythm = null;

  const rhythmData = AUDIO_DATA[rhythm] || {};
  if (!Object.keys(rhythmData).length) {
    playBtn.disabled = true;
    playBtn.innerHTML = 'No audio';
    return;
  }

  playBtn.disabled = true;
  playBtn.innerHTML = 'Loading\u2026';

  const loads = INST_KEYS.map(inst => new Promise(resolve => {
    const dataUri = rhythmData[inst];
    if (!dataUri) { resolve(); return; }
    const audio = new Audio();
    audio.loop  = true;
    audio.preservesPitch      = true;
    audio.mozPreservePitch    = true;
    audio.webkitPreservePitch = true;
    audio.src = dataUri;
    audio.addEventListener('canplaythrough', () => {
      stemAudio[inst] = audio;
      const src = audioCtx.createMediaElementSource(audio);
      src.connect(instGains[inst]);
      stemSrcs[inst] = src;
      resolve();
    }, { once: true });
    audio.addEventListener('error', () => { resolve(); }, { once: true });
    audio.load();
  }));

  await Promise.all(loads);
  loadedRhythm = rhythm;
  playBtn.disabled = false;
  playBtn.innerHTML = '&#9654; Play';
}

// ── Mixer: show / hide ───────────────────────────────────────────────────
async function showMixer(rhythm) {
  mixer.removeAttribute('hidden');
  mixerRhythmLbl.textContent = RHYTHM_LABELS[rhythm] || rhythm;
  ensureAudioCtx();
  await loadStems(rhythm);
}
function hideMixer() {
  mixer.setAttribute('hidden', '');
  stopPlayback();
}

// ── Play / Pause button ───────────────────────────────────────────────────
playBtn.addEventListener('click', () => {
  if (!activeRhythm || activeRhythm === 'all') return;
  if (audioCtx && audioCtx.state === 'suspended') audioCtx.resume();
  if (isPlaying) { stopPlayback(); } else { startPlayback(); }
});

function startPlayback() {
  if (loadedRhythm !== activeRhythm) return;
  INST_KEYS.forEach(inst => {
    const audio = stemAudio[inst];
    if (!audio) return;
    audio.playbackRate = playbackRate;
    audio.play().catch(() => {});
  });
  isPlaying = true;
  playBtn.classList.add('playing');
  playBtn.innerHTML = '&#9646;&#9646; Pause';
}

function stopPlayback() {
  INST_KEYS.forEach(inst => {
    if (stemAudio[inst]) { stemAudio[inst].pause(); stemAudio[inst].currentTime = 0; }
  });
  isPlaying = false;
  playBtn.classList.remove('playing');
  playBtn.innerHTML = '&#9654; Play';
}

// ── Instrument toggle ────────────────────────────────────────────────────
instBtns.forEach(btn => {
  btn.addEventListener('click', () => {
    const inst = btn.dataset.inst;
    mutedMap[inst] = !mutedMap[inst];
    btn.classList.toggle('muted',  mutedMap[inst]);
    btn.classList.toggle('active', !mutedMap[inst]);
    if (instGains[inst]) {
      instGains[inst].gain.value = mutedMap[inst] ? 0 : volumeMap[inst];
    }
  });
});

// ── Speed slider ─────────────────────────────────────────────────────────
speedSlider.addEventListener('input', () => {
  playbackRate = parseFloat(speedSlider.value);
  speedDisplay.textContent = playbackRate.toFixed(1) + '\u00d7';
  INST_KEYS.forEach(inst => {
    if (stemAudio[inst]) stemAudio[inst].playbackRate = playbackRate;
  });
});

// ── Per-instrument volume sliders ─────────────────────────────────────────
volSliders.forEach(slider => {
  slider.addEventListener('input', () => {
    const inst = slider.dataset.inst;
    volumeMap[inst] = parseInt(slider.value, 10) / 100;
    if (instGains[inst] && !mutedMap[inst]) {
      instGains[inst].gain.value = volumeMap[inst];
    }
  });
});

// ── Master volume slider ──────────────────────────────────────────────────
masterVolSlider.addEventListener('input', () => {
  masterVolume = parseInt(masterVolSlider.value, 10) / 100;
  masterVolDisplay.textContent = masterVolSlider.value + '%';
  if (masterGainNode) masterGainNode.gain.value = masterVolume;
});

// ── Search ────────────────────────────────────────────────────────────────
searchInput.addEventListener('input', () => {
  searchQuery = searchable(searchInput.value.trim());
  renderSongs();
});

// ── Helpers ───────────────────────────────────────────────────────────────

/** Strip **bold** markers, normalise diacritics, collapse whitespace, lowercase. */
function searchable(str) {
  return str
    .replace(/\*\*/g, '')
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ')
    .toLowerCase();
}

function esc(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

/** Render lyrics text: escape HTML, convert **bold** markers to <strong>. */
function renderLyrics(text) {
  return esc(text).replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
}

// ── Filter songs ──────────────────────────────────────────────────────────
function getFilteredSongs() {
  return SONGS_DB.filter(song => {
    // Category filter
    if (activeCategory !== 'all' && song.category !== activeCategory) return false;

    // Sub-rhythm filter (capoeira only, and not when 'all' rhythm selected)
    if (activeCategory === 'capoeira' && activeRhythm && activeRhythm !== 'all') {
      if (!song.rhythm_tags.includes(activeRhythm)) return false;
    }

    // Search filter
    if (searchQuery) {
      const haystack = searchable(song.title + ' ' + song.lyrics_pt + ' ' + song.lyrics_en);
      if (!haystack.includes(searchQuery)) return false;
    }

    return true;
  });
}

// ── Render a single song card ─────────────────────────────────────────────
function renderCard(song) {
  const card = document.createElement('article');
  card.className = 'song-card';
  card.dataset.id = song.id;

  const tagsHtml = song.rhythm_tags.length
    ? song.rhythm_tags.map(t => '<span class="rhythm-badge">' + esc(t) + '</span>').join('')
    : '';

  const tipHtml = song.tip
    ? '<div class="tip-section"><span class="tip-label">Tip:</span>' + esc(song.tip) + '</div>'
    : '';

  const ptHtml = song.lyrics_pt
    ? '<div class="lyrics-section"><div class="lyrics-label">Portugu\u00eas</div><div class="lyrics-pt">' + renderLyrics(song.lyrics_pt) + '</div></div>'
    : '';

  const enHtml = song.lyrics_en
    ? '<div class="lyrics-section"><div class="lyrics-label">English</div><div class="lyrics-en">' + renderLyrics(song.lyrics_en) + '</div></div>'
    : '';

  var linkCls = song.youtube_id ? 'has-link' : 'no-link';
  card.innerHTML =
    '<div class="song-header" role="button" aria-expanded="false" tabindex="0">' +
      '<div class="song-actions">' +
        '<button class="song-action-btn song-play-btn ' + linkCls + '" title="Play" aria-label="Play ' + esc(song.title) + '">' +
          '<svg viewBox="0 0 10 12" width="11" height="11"><path d="M0 0 L10 6 L0 12 Z" fill="currentColor"/></svg>' +
        '</button>' +
        '<button class="song-action-btn song-queue-btn ' + linkCls + '" title="Add to queue" aria-label="Add to queue: ' + esc(song.title) + '">' +
          '<svg viewBox="0 0 14 14" width="13" height="13"><rect x="0" y="1" width="9" height="2" rx="1" fill="currentColor"/><rect x="0" y="6" width="9" height="2" rx="1" fill="currentColor"/><rect x="0" y="11" width="6" height="2" rx="1" fill="currentColor"/><rect x="11" y="9" width="2" height="6" rx="1" fill="currentColor"/><rect x="8" y="12" width="8" height="2" rx="1" fill="currentColor"/></svg>' +
        '</button>' +
      '</div>' +
      '<div class="song-title-wrap">' +
        '<span class="song-title">' + esc(song.title) + '</span>' +
        (tagsHtml ? '<div class="song-rhythm-tags">' + tagsHtml + '</div>' : '') +
      '</div>' +
      '<span class="song-chevron" aria-hidden="true">\u25bc</span>' +
    '</div>' +
    '<div class="song-body" role="region" aria-label="' + esc(song.title) + ' lyrics">' +
      ptHtml + enHtml + tipHtml +
    '</div>';

  const header = card.querySelector('.song-header');
  function toggle() {
    const isOpen = card.classList.toggle('open');
    header.setAttribute('aria-expanded', isOpen);
  }
  header.addEventListener('click', toggle);
  header.addEventListener('keydown', e => {
    if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); toggle(); }
  });

  card.querySelector('.song-play-btn').addEventListener('click', e => {
    e.stopPropagation();
    playSong(song);
  });
  card.querySelector('.song-queue-btn').addEventListener('click', e => {
    e.stopPropagation();
    queueSong(song);
  });

  return card;
}

/** Render story text: italic paragraphs, with optional author attribution below. */
function renderStory(text, author) {
  const paras = text.split('\n\n')
    .map(p => '<p><em>' + esc(p.trim()) + '</em></p>')
    .join('');
  const attribution = author
    ? '<div class="story-author">\u2014 ' + esc(author) + '</div>'
    : '';
  return paras + attribution;
}

// ── Render a single ladainha card ────────────────────────────────────────
function renderLadainhaCard(ladainha) {
  const card = document.createElement('article');
  card.className = 'song-card';
  card.dataset.id = 'l' + ladainha.id;

  const ptHtml = ladainha.lyrics_pt
    ? '<div class="lyrics-section"><div class="lyrics-label">Portugu\u00eas</div><div class="lyrics-pt">' + renderLyrics(ladainha.lyrics_pt) + '</div></div>'
    : '';
  const authorHtml = ladainha.author
    ? '<div class="ladainha-author">Author: ' + esc(ladainha.author) + '</div>'
    : '';

  const enHtml = ladainha.lyrics_en
    ? '<div class="lyrics-section"><div class="lyrics-label">English</div><div class="lyrics-en">' + renderLyrics(ladainha.lyrics_en) + '</div></div>'
    : '';

  var ladLinkCls = ladainha.youtube_id ? 'has-link' : 'no-link';
  card.innerHTML =
    '<div class="song-header" role="button" aria-expanded="false" tabindex="0">' +
      '<div class="song-actions">' +
        '<button class="song-action-btn song-play-btn ' + ladLinkCls + '" title="Play" aria-label="Play ' + esc(ladainha.title) + '">' +
          '<svg viewBox="0 0 10 12" width="11" height="11"><path d="M0 0 L10 6 L0 12 Z" fill="currentColor"/></svg>' +
        '</button>' +
        '<button class="song-action-btn song-queue-btn ' + ladLinkCls + '" title="Add to queue" aria-label="Add to queue: ' + esc(ladainha.title) + '">' +
          '<svg viewBox="0 0 14 14" width="13" height="13"><rect x="0" y="1" width="9" height="2" rx="1" fill="currentColor"/><rect x="0" y="6" width="9" height="2" rx="1" fill="currentColor"/><rect x="0" y="11" width="6" height="2" rx="1" fill="currentColor"/><rect x="11" y="9" width="2" height="6" rx="1" fill="currentColor"/><rect x="8" y="12" width="8" height="2" rx="1" fill="currentColor"/></svg>' +
        '</button>' +
      '</div>' +
      '<div class="song-title-wrap">' +
        '<span class="song-title">' + esc(ladainha.title) + '</span>' +
      '</div>' +
      '<span class="song-chevron" aria-hidden="true">\u25bc</span>' +
    '</div>' +
    '<div class="song-body ladainha-body" role="region" aria-label="' + esc(ladainha.title) + '">' +
      '<div class="ladainha-lyrics-col">' +
        ptHtml + enHtml + authorHtml +
      '</div>' +
      '<div class="ladainha-info-col">' +
        '<div class="ladainha-info-block">' +
          '<div class="lyrics-label">Story of this Ladainha</div>' +
          '<div class="ladainha-info-text">' + renderStory(ladainha.story, ladainha.story_author) + '</div>' +
        '</div>' +
        '<div class="ladainha-info-block">' +
          '<div class="lyrics-label">Moral of this Ladainha</div>' +
          '<div class="ladainha-info-text">' + esc(ladainha.moral) + '</div>' +
        '</div>' +
      '</div>' +
    '</div>';

  const header = card.querySelector('.song-header');
  function toggle() {
    const isOpen = card.classList.toggle('open');
    header.setAttribute('aria-expanded', isOpen);
  }
  header.addEventListener('click', toggle);
  header.addEventListener('keydown', e => {
    if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); toggle(); }
  });

  card.querySelector('.song-play-btn').addEventListener('click', e => {
    e.stopPropagation();
    playSong(ladainha);
  });
  card.querySelector('.song-queue-btn').addEventListener('click', e => {
    e.stopPropagation();
    queueSong(ladainha);
  });

  return card;
}

// ── Render the full song list ─────────────────────────────────────────────
function renderSongs() {
  songList.innerHTML = '';

  // Ladainha tab uses its own database and card layout
  if (activeCategory === 'capoeira' && activeRhythm === 'ladainha') {
    const list = searchQuery
      ? LADAINHAS_DB.filter(l => searchable(l.title + ' ' + l.lyrics_pt + ' ' + l.lyrics_en + ' ' + l.story + ' ' + l.moral).includes(searchQuery))
      : LADAINHAS_DB;

    if (!list.length) {
      const msg = document.createElement('div');
      msg.className = 'empty-msg';
      msg.innerHTML = '<span class="empty-icon">\ud83d\udd0d</span>No ladainhas match your search.';
      songList.appendChild(msg);
      return;
    }

    const fragment = document.createDocumentFragment();
    list.forEach(l => fragment.appendChild(renderLadainhaCard(l)));
    songList.appendChild(fragment);
    return;
  }

  const songs = getFilteredSongs();

  if (!songs.length) {
    const msg = document.createElement('div');
    msg.className = 'empty-msg';

    if (searchQuery) {
      msg.innerHTML = '<span class="empty-icon">\ud83d\udd0d</span>No songs match your search.';
    } else if (activeCategory === 'all') {
      msg.innerHTML = '<span class="empty-icon">\ud83c\udfb6</span>No songs found.';
    } else if (activeCategory === 'samba') {
      msg.innerHTML = '<span class="empty-icon">\ud83c\udfb5</span>No Samba songs tagged yet.<br>Rhythm tags can be added in <code>songs_db.js</code>.';
    } else if (activeCategory === 'maculele') {
      msg.innerHTML = '<span class="empty-icon">\ud83c\udfb5</span>No Maculel\u00ea songs tagged yet.<br>Rhythm tags can be added in <code>songs_db.js</code>.';
    } else if (activeRhythm && activeRhythm !== 'all') {
      msg.innerHTML = '<span class="empty-icon">\ud83c\udfb6</span>No songs tagged for this rhythm yet.';
    } else {
      msg.innerHTML = '<span class="empty-icon">\ud83c\udfb6</span>No songs found.';
    }

    songList.appendChild(msg);
    return;
  }

  const fragment = document.createDocumentFragment();
  songs.forEach(song => fragment.appendChild(renderCard(song)));
  songList.appendChild(fragment);
}

// ── Video queue ───────────────────────────────────────────────────────────
const videoQueue = [];   // [{videoId, title}] — upcoming videos
let   currentVideoId    = null;
let   currentVideoTitle = null;
let   ytPlayer          = null;
let   ytApiReady        = false;

// Load YouTube IFrame API
(function () {
  const tag = document.createElement('script');
  tag.src = 'https://www.youtube-nocookie.com/iframe_api';
  document.head.appendChild(tag);
})();

window.onYouTubeIframeAPIReady = function () {
  ytApiReady = true;
};

function extractVideoId(url) {
  try {
    const u = new URL(url.trim());
    if (u.hostname.includes('youtube.com')) {
      return u.searchParams.get('v') || u.pathname.split('/').pop() || null;
    }
    if (u.hostname.includes('youtu.be')) {
      return u.pathname.slice(1, 12) || null;
    }
  } catch(e) {}
  return null;
}

function showVideoPlaceholder() {
  videoPlayerArea.innerHTML =
    '<div class="video-placeholder-inner">' +
      '<div class="video-placeholder-icon">&#9654;</div>' +
      '<div>Select a song from the list.</div>' +
      '<div style="font-size:0.7rem;margin-top:6px">A red X marks songs that have not yet been added to the video player.</div>' +
    '</div>';
}

function playVideo(videoId, title) {
  currentVideoId    = videoId;
  currentVideoTitle = title;
  nowPlayingTitle.textContent = title;

  if (ytPlayer && typeof ytPlayer.loadVideoById === 'function') {
    ytPlayer.loadVideoById(videoId);
  } else if (ytApiReady) {
    videoPlayerArea.innerHTML = '<div id="yt-player-div" style="position:absolute;inset:0;"></div>';
    ytPlayer = new YT.Player('yt-player-div', {
      width: '100%', height: '100%',
      videoId: videoId,
      playerVars: { autoplay: 1, rel: 0, modestbranding: 1, host: 'https://www.youtube-nocookie.com' },
      events: {
        onReady: function (e) {
          const data = e.target.getVideoData();
          if (data && data.title) {
            currentVideoTitle = data.title;
            nowPlayingTitle.textContent = data.title;
            renderQueue();
          }
        },
        onStateChange: function (e) {
          if (e.data === YT.PlayerState.ENDED) playNext();
        }
      }
    });
  } else {
    // YT API not loaded — plain iframe fallback
    videoPlayerArea.innerHTML =
      '<iframe src="https://www.youtube-nocookie.com/embed/' + videoId +
      '?autoplay=1&rel=0" frameborder="0" allow="autoplay;encrypted-media" allowfullscreen ' +
      'referrerpolicy="strict-origin-when-cross-origin" ' +
      'style="position:absolute;inset:0;width:100%;height:100%;border:none;"></iframe>';
  }
  renderQueue();
}

function playNext() {
  if (videoQueue.length > 0) {
    const next = videoQueue.shift();
    playVideo(next.videoId, next.title);
  } else {
    currentVideoId = currentVideoTitle = null;
    nowPlayingTitle.textContent = '\u2014';
    if (ytPlayer && typeof ytPlayer.stopVideo === 'function') {
      ytPlayer.stopVideo();
    }
    showVideoPlaceholder();
    renderQueue();
  }
}

function removeFromQueue(idx) {
  videoQueue.splice(idx, 1);
  renderQueue();
}

function playFromQueue(idx) {
  const item = videoQueue.splice(idx, 1)[0];
  playVideo(item.videoId, item.title);
}

let dragSrcIdx = null;

function renderQueue() {
  const filled = videoQueue.length;
  const empty  = Math.max(0, 5 - filled);
  let html = '';

  for (let i = 0; i < filled; i++) {
    html +=
      '<div class="queue-item queue-filled" draggable="true" data-idx="' + i + '">' +
        '<span class="queue-drag-handle" aria-hidden="true">&#8942;</span>' +
        '<span class="queue-item-num">' + (i + 1) + '</span>' +
        '<span class="queue-item-title">' + esc(videoQueue[i].title) + '</span>' +
        '<button class="queue-play-now-btn" data-idx="' + i + '" aria-label="Play now" title="Play now">&#9654;</button>' +
        '<button class="queue-remove-btn" data-idx="' + i + '" aria-label="Remove">&#x2715;</button>' +
      '</div>';
  }

  for (let i = 0; i < empty; i++) {
    html +=
      '<div class="queue-item queue-empty">' +
        '<span class="queue-add-icon">+</span>' +
        '<span class="queue-add-text">Queue a song</span>' +
      '</div>';
  }

  queueListEl.innerHTML = html;

  // Play-now buttons
  queueListEl.querySelectorAll('.queue-play-now-btn').forEach(function (btn) {
    btn.addEventListener('click', function (e) {
      e.stopPropagation();
      playFromQueue(parseInt(btn.dataset.idx, 10));
    });
  });

  // Remove buttons
  queueListEl.querySelectorAll('.queue-remove-btn').forEach(function (btn) {
    btn.addEventListener('click', function (e) {
      e.stopPropagation();
      removeFromQueue(parseInt(btn.dataset.idx, 10));
    });
  });

  // Drag-and-drop reorder
  queueListEl.querySelectorAll('.queue-filled').forEach(function (item) {
    item.addEventListener('dragstart', function (e) {
      dragSrcIdx = parseInt(item.dataset.idx, 10);
      item.classList.add('dragging');
      e.dataTransfer.effectAllowed = 'move';
    });
    item.addEventListener('dragend', function () {
      item.classList.remove('dragging');
      queueListEl.querySelectorAll('.queue-filled').forEach(function (el) {
        el.classList.remove('drag-over');
      });
    });
    item.addEventListener('dragenter', function (e) {
      e.preventDefault();
      item.classList.add('drag-over');
    });
    item.addEventListener('dragleave', function () {
      item.classList.remove('drag-over');
    });
    item.addEventListener('dragover', function (e) {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
    });
    item.addEventListener('drop', function (e) {
      e.preventDefault();
      item.classList.remove('drag-over');
      const targetIdx = parseInt(item.dataset.idx, 10);
      if (dragSrcIdx === null || dragSrcIdx === targetIdx) return;
      const moved = videoQueue.splice(dragSrcIdx, 1)[0];
      videoQueue.splice(targetIdx, 0, moved);
      dragSrcIdx = null;
      renderQueue();
    });
  });
}

// ── Song → video bridge (stubs — wire up YouTube IDs here later) ─────────
function playSong(song) {
  // TODO: replace null with the song's YouTube video ID
  const videoId = song.youtube_id || null;
  const title   = song.title;
  if (!videoId) {
    console.log('[VIDEO] No YouTube ID yet for:', title);
    return;
  }
  playVideo(videoId, title);
}

function queueSong(song) {
  // TODO: replace null with the song's YouTube video ID
  const videoId = song.youtube_id || null;
  const title   = song.title;
  if (!videoId) {
    console.log('[VIDEO] No YouTube ID yet for:', title);
    return;
  }
  if (!currentVideoId) {
    playVideo(videoId, title);
  } else {
    videoQueue.push({ videoId: videoId, title: title });
    renderQueue();
  }
}

// ── Initial render ────────────────────────────────────────────────────────
showVideoPlaceholder();
renderQueue();
renderSongs();
